    pattern_type character varying(50),
    department_cd character varying(20),
    role_cd character varying(20),
    description text,
    typical_gpa_range character varying(20),
    key_courses character varying(20)[],
    key_activities character varying(200)[],
    key_skills character varying(20)[],
    timeline jsonb,
    success_rate numeric(5,2),
    sample_size integer,
    ins_user_id character varying(50),
    ins_dt timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    upd_user_id character varying(50),
    upd_dt timestamp without time zone
);


ALTER TABLE idino_career.tb_success_pattern OWNER TO postgres;

--
-- Name: tb_term; Type: TABLE; Schema: idino_career; Owner: postgres
--

CREATE TABLE idino_career.tb_term (
    term_cd character varying(10) NOT NULL,
    term_nm character varying(50) NOT NULL,
    start_date date NOT NULL,
    end_date date NOT NULL,
    registration_start date,
    registration_end date,
    use_fg character(1) DEFAULT 'Y'::bpchar,
    ins_user_id character varying(50),
    ins_dt timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    upd_user_id character varying(50),
    upd_dt timestamp without time zone
);


ALTER TABLE idino_career.tb_term OWNER TO postgres;

--
-- Name: tb_university; Type: TABLE; Schema: idino_career; Owner: postgres
