    university_nm_en character varying(100),
    address character varying(500),
    phone character varying(20),
    website character varying(200),
    use_fg character(1) DEFAULT 'Y'::bpchar,
    ins_user_id character varying(50),
    ins_user_ip character varying(50),
    ins_dt timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    upd_user_id character varying(50),
    upd_dt timestamp without time zone,
    ins_system_gcd character varying(10),
    ins_menu_cd character varying(20),
